<?php
if (!defined('ABSPATH')) { exit; }
class GPSUMA_Frontend {
 public function __construct(){ add_shortcode('gpsuma_area_cliente',array($this,'area_cliente')); add_action('wp_enqueue_scripts',array($this,'assets')); }
 public function assets(){ if(!is_singular())return; global $post; if($post&&has_shortcode($post->post_content,'gpsuma_area_cliente')) wp_enqueue_style('gpsuma-frontend',GPSUMA_URL.'assets/css/frontend.css',array(),GPSUMA_VERSION); }

 private function normalize_ticket_uploads() {
  $nonce = isset( $_POST['gpsuma_richiesta_nonce'] ) ? sanitize_text_field( wp_unslash( $_POST['gpsuma_richiesta_nonce'] ) ) : '';
  if ( ! $nonce || ! wp_verify_nonce( $nonce, 'gpsuma_invia_richiesta' ) ) { return array(); }
  if ( empty( $_FILES['allegati'] ) || ! is_array( $_FILES['allegati'] ) ) { return array(); }
  // phpcs:disable WordPress.Security.ValidatedSanitizedInput.InputNotSanitized -- Upload metadata is validated and passed to WordPress media_handle_upload(), which performs MIME and file validation.
  $group = $_FILES['allegati'];
  // phpcs:enable WordPress.Security.ValidatedSanitizedInput.InputNotSanitized
  $required = array( 'name', 'type', 'tmp_name', 'error', 'size' );
  foreach ( $required as $field ) { if ( ! isset( $group[$field] ) || ! is_array( $group[$field] ) ) { return array(); } }
  $files = array();
  foreach ( array_keys( $group['name'] ) as $key ) {
   if ( ! isset( $group['name'][$key], $group['type'][$key], $group['tmp_name'][$key], $group['error'][$key], $group['size'][$key] ) ) { continue; }
   $name = sanitize_file_name( wp_unslash( $group['name'][$key] ) );
   if ( '' === $name ) { continue; }
   $files[] = array(
    'name' => $name,
    'type' => sanitize_mime_type( wp_unslash( $group['type'][$key] ) ),
    'tmp_name' => sanitize_text_field( wp_unslash( $group['tmp_name'][$key] ) ),
    'error' => absint( $group['error'][$key] ),
    'size' => absint( $group['size'][$key] ),
   );
  }
  return $files;
 }

 public function area_cliente(){
  if(!is_user_logged_in()){ ob_start(); ?><div class="gpsuma-portal gpsuma-portal-login"><?php if(has_custom_logo()): ?><div class="gpsuma-login-brand"><?php echo wp_kses_post( get_custom_logo() ); ?></div><?php endif; ?><span class="gpsuma-eyebrow">Portale clienti</span><h2>Area assistenza</h2><p>Accedi con le credenziali ricevute per consultare dispositivi, interventi, pacchetti e richieste.</p><?php wp_login_form(array('redirect'=>get_permalink(),'label_username'=>'Email o nome utente','label_password'=>'Password','label_remember'=>'Ricordami','label_log_in'=>'Accedi','remember'=>true)); ?></div><?php return ob_get_clean(); }
  $db=new GPSUMA_DB(); $uid=get_current_user_id();
  $c=$db->get_portal_customer($uid);
