   $oggetto=sanitize_text_field(wp_unslash($_POST['oggetto']??'')); $descrizione=sanitize_textarea_field(wp_unslash($_POST['descrizione']??'')); $dispositivo_id=absint($_POST['dispositivo_id']??0); $priorita=sanitize_text_field(wp_unslash($_POST['priorita']??'Normale'));
   $device=$dispositivo_id?$db->get_portal_device($dispositivo_id,$c->id):null; $dispositivo=$device?trim($device->tipo.' '.$device->marca.' '.$device->modello):'';
