Priorità: {$priorita}

{$descrizione}"); $request_notice='<div class="gpsuma-success">Ticket #'.$ticket_id.' inviato correttamente.</div>'; } else $request_notice='<div class="gpsuma-alert">Non è stato possibile inviare il ticket.</div>'; } else { $request_notice='<div class="gpsuma-alert">Compila oggetto e descrizione.</div>'; }
  }
  if(isset($_POST['gpsuma_commenta_ticket']) && isset($_POST['gpsuma_commento_nonce']) && wp_verify_nonce(sanitize_text_field(wp_unslash($_POST['gpsuma_commento_nonce'])),'gpsuma_commenta_ticket')){
   $ticket_id=absint($_POST['ticket_id']??0); $messaggio=sanitize_textarea_field(wp_unslash($_POST['messaggio']??'')); $owned=$db->portal_ticket_belongs_to_customer($ticket_id,$c->id);
   if($owned && $messaggio){ $u=wp_get_current_user(); $db->add_portal_ticket_comment(array('richiesta_id'=>$ticket_id,'autore_user_id'=>$uid,'autore_nome'=>$u->display_name?:$c->nome,'tipo_autore'=>'cliente','messaggio'=>$messaggio,'visibile_cliente'=>1,'data_creazione'=>current_time('mysql'))); $db->touch_ticket($ticket_id); wp_mail(get_option('admin_email'),'Nuovo commento ticket #'.$ticket_id,$messaggio); $request_notice='<div class="gpsuma-success">Commento inviato.</div>'; }
  }
  $portal=$db->get_portal_data($c->id);
  $ds=$portal['devices']; $ps=$portal['packages']; $contracts=$portal['contracts']; $qs=$portal['tickets']; $is=$portal['interventions']; $attachments=$portal['intervention_attachments']; $deadlines=$portal['deadlines']; $ticket_comments=$portal['ticket_comments']; $ticket_attachments=$portal['ticket_attachments'];
  ob_start(); ?><div class="gpsuma-portal"><div class="gpsuma-portal-header"><div class="gpsuma-brand-row"><?php if(has_custom_logo()): ?><div class="gpsuma-brand-logo"><?php echo wp_kses_post( get_custom_logo() ); ?></div><?php endif; ?><div><span class="gpsuma-eyebrow">Area riservata</span><h2>Benvenuto, <?php echo esc_html($c->nome); ?></h2></div></div><a class="gpsuma-logout" href="<?php echo esc_url(wp_logout_url(get_permalink())); ?>">Esci</a></div>
  <nav class="gpsuma-portal-nav" aria-label="Navigazione area cliente"><a href="#gpsuma-dati">I tuoi dati</a><a href="#gpsuma-dispositivi">Dispositivi</a><?php if($ps): ?><a href="#gpsuma-pacchetti">Pacchetti</a><?php endif; ?><?php if($contracts): ?><a href="#gpsuma-contratti">Contratti</a><?php endif; ?><?php if($deadlines): ?><a href="#gpsuma-scadenze">Scadenze</a><?php endif; ?><a href="#gpsuma-richieste">Richiedi assistenza</a><a href="#gpsuma-interventi">Interventi</a></nav>
  <?php echo wp_kses_post( $request_notice ); ?>
  <div class="gpsuma-portal-stats"><div><strong><?php echo count($ds); ?></strong><span>Dispositivi</span></div><div><strong><?php echo count($is); ?></strong><span>Interventi</span></div><div><strong><?php echo count($qs); ?></strong><span>Ticket</span></div><div><strong><?php echo count($ps); ?></strong><span>Pacchetti</span></div><div><strong><?php echo count($contracts); ?></strong><span>Contratti</span></div></div>
