  <section id="gpsuma-dispositivi" class="gpsuma-panel"><div class="gpsuma-panel-title"><h3>I tuoi dispositivi</h3><span class="gpsuma-count"><?php echo count($ds); ?></span></div><div class="gpsuma-device-list"><?php if(!$ds): ?><p>Nessun dispositivo associato.</p><?php endif; foreach($ds as $d): ?><article class="gpsuma-device-card"><span class="gpsuma-device-icon">💻</span><div><h4><?php echo esc_html(trim($d->tipo.' '.$d->marca.' '.$d->modello)); ?></h4><span class="gpsuma-device-status gpsuma-device-status-<?php echo esc_attr(sanitize_title($d->stato ?: 'Operativo')); ?>"><?php echo esc_html($d->stato ?: 'Operativo'); ?></span><p><strong>Seriale:</strong> <?php echo esc_html($d->seriale?:'—'); ?></p><p><strong>Sistema:</strong> <?php echo esc_html($d->sistema?:'—'); ?></p></div></article><?php endforeach; ?></div></section></div>
  <?php if($ps): ?><section id="gpsuma-pacchetti" class="gpsuma-panel gpsuma-packages"><div class="gpsuma-panel-title"><h3>Pacchetti assistenza</h3><span class="gpsuma-count"><?php echo count($ps); ?></span></div><div class="gpsuma-package-list"><?php foreach($ps as $p): $used=(int)$p->utilizzati; $unlimited=!empty($p->interventi_illimitati); $total=(int)$p->interventi_inclusi; $remaining=$unlimited?null:max(0,$total-$used); $percent=(!$unlimited&&$total)?min(100,round($used/$total*100)):0; ?><article class="gpsuma-package-card"><div class="gpsuma-package-top"><div><h4><?php echo esc_html($p->nome); ?></h4><span class="gpsuma-package-status"><?php echo esc_html($p->stato); ?></span></div><strong><?php echo $unlimited ? '∞ Illimitati' : esc_html($remaining).' residui'; ?></strong></div><div class="gpsuma-package-numbers"><span><?php echo esc_html($used); ?> utilizzati</span><span><?php echo $unlimited ? 'Nessun limite' : esc_html($total).' inclusi'; ?></span></div><?php if(!$unlimited): ?><div class="gpsuma-frontend-progress"><span style="width:<?php echo esc_attr($percent); ?>%"></span></div><?php endif; ?><?php if($p->data_scadenza): ?><p class="gpsuma-package-expiry">Scadenza: <?php echo esc_html(date_i18n('d/m/Y',strtotime($p->data_scadenza))); ?></p><?php endif; ?></article><?php endforeach; ?></div></section><?php endif; ?>
  <?php if($contracts): ?><section id="gpsuma-contratti" class="gpsuma-panel gpsuma-packages"><div class="gpsuma-panel-title"><h3>Contratti di assistenza</h3><span class="gpsuma-count"><?php echo count($contracts); ?></span></div><div class="gpsuma-package-list"><?php foreach($contracts as $contract): $hours=round((float)$contract->minuti_usati/60,2); $unlimited=!empty($contract->interventi_illimitati); $remaining_interventions=$unlimited?null:max(0,(int)$contract->interventi_inclusi-(int)$contract->interventi_usati); ?><article class="gpsuma-package-card"><div class="gpsuma-package-top"><div><h4><?php echo esc_html($contract->nome); ?></h4><span class="gpsuma-package-status"><?php echo esc_html($contract->stato.' · '.$contract->tipo); ?></span></div><strong><?php echo esc_html(number_format_i18n((float)$contract->valore_contratto,2).' €'); ?></strong></div><div class="gpsuma-package-numbers"><span>Dal <?php echo esc_html(date_i18n('d/m/Y',strtotime($contract->data_inizio))); ?></span><span><?php echo $contract->data_fine?'Al '.esc_html(date_i18n('d/m/Y',strtotime($contract->data_fine))):'Senza scadenza'; ?></span></div><?php if((float)$contract->ore_incluse>0): ?><p><strong>Ore:</strong> <?php echo esc_html($hours.' / '.$contract->ore_incluse); ?> utilizzate</p><?php endif; ?><?php if($unlimited): ?><p><strong>Interventi:</strong> ∞ Illimitati (<?php echo esc_html((int)$contract->interventi_usati); ?> registrati)</p><?php elseif((int)$contract->interventi_inclusi>0): ?><p><strong>Interventi:</strong> <?php echo esc_html((int)$contract->interventi_usati.' / '.(int)$contract->interventi_inclusi); ?> — <?php echo esc_html($remaining_interventions); ?> residui</p><?php endif; ?><?php if($contract->servizi_inclusi): ?><p><strong>Servizi inclusi:</strong><br><?php echo nl2br(esc_html($contract->servizi_inclusi)); ?></p><?php endif; ?><?php if($contract->esclusioni): ?><p><strong>Esclusioni:</strong><br><?php echo nl2br(esc_html($contract->esclusioni)); ?></p><?php endif; ?></article><?php endforeach; ?></div></section><?php endif; ?>
  <?php if($deadlines): ?><section id="gpsuma-scadenze" class="gpsuma-panel gpsuma-deadlines"><div class="gpsuma-panel-title"><h3>Scadenze</h3><span class="gpsuma-count"><?php echo count($deadlines); ?></span></div><div class="gpsuma-deadline-list"><?php foreach($deadlines as $sc): $days=(int)floor((strtotime($sc->data_scadenza)-strtotime(current_time('Y-m-d')))/DAY_IN_SECONDS); ?><article class="<?php echo $days<0?'is-expired':($days<=(int)$sc->preavviso_giorni?'is-due':''); ?>"><div><strong><?php echo esc_html($sc->titolo); ?></strong><span><?php echo esc_html($sc->tipo); ?><?php if($sc->dispositivo_nome): ?> · <?php echo esc_html($sc->dispositivo_nome); ?><?php endif; ?></span></div><div><strong><?php echo esc_html(date_i18n('d/m/Y',strtotime($sc->data_scadenza))); ?></strong><small><?php echo $days<0?esc_html('Scaduta da '.abs($days).' giorni'):esc_html('Tra '.$days.' giorni'); ?></small></div></article><?php endforeach; ?></div></section><?php endif; ?>
